#include <iostream>
#include <string>
#include <vector>

// Abstract base class Animal
class Animal {
public:
    // Pure virtual method
    virtual void makeSound() = 0;

    // No virtual destructor! This is the robustness issue.
    // If derived classes have resources allocated on the heap,
    // deleting them via an an Animal* pointer will lead to memory leaks.
    ~Animal() {}
};

// Concrete class Dog
class Dog : public Animal {
private:
    std::string* name_tag; 

public:
    Dog(const std::string& name) : name_tag(new std::string(name)) {}

    void makeSound() override {
        std::cout << "Woof! (from " << *name_tag << ")" << std::endl;
    }

    ~Dog() {
        delete name_tag;
    }
};

// Concrete class Cat
class Cat : public Animal {
private:
    std::string* favorite_toy; 

public:
    Cat(const std::string& toy) : favorite_toy(new std::string(toy)) {}

    void makeSound() override {
        std::cout << "Meow! (playing with " << *favorite_toy << ")" << std::endl;
    }

    ~Cat() {
        delete favorite_toy;
    }
};

int main() {
    Animal* myDog = new Dog("Buddy");
    Animal* myCat = new Cat("Yarn Ball");

    myDog->makeSound();
    myCat->makeSound();

    delete myDog;
    delete myCat;

    Dog stackDog("Rex");
    Cat stackCat("Mouse");
    stackDog.makeSound();
    stackCat.makeSound();

    return 0;
}
